#include <stdio.h>
#define MOD 1000000007
long long dp[100005];
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        dp[1] = 1;
        for (int i = 2; i <= N; i++) {
            dp[i] = ((1LL << (i-1)) - 1) * dp[i-1] % MOD + dp[i-1];
            dp[i] %= MOD;
        }
        printf("%lld\n", dp[N]);
    }
    return 0;
}

