        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            dp[1] = 1;
            for (int i = 2; i <= N; i++) {
                dp[i] = ((1L << (i-1)) - 1) * dp[i-1] % MOD + dp[i-1];
                dp[i] %= MOD;
            }
            System.out.println(dp[N]);
        }
    }
}

